import React from 'react';
import { Link } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { useAuth } from '../../context/AuthContext';

export default function AccountHome() {
  const { user } = useAuth();

  return (
    <div>
      <Helmet>
        <title>Account overview | Nova Shop</title>
      </Helmet>
      <h2 style={{ fontSize: '1.25rem', marginBottom: '0.75rem' }}>Welcome back</h2>
      <p style={{ color: 'var(--gray)', marginBottom: '1.5rem' }}>
        Signed in as <strong>{user?.email}</strong>
      </p>
      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.75rem' }}>
        <Link to="/account/orders" className="btn btn-outline btn-sm">
          View orders
        </Link>
        <Link to="/account/profile" className="btn btn-outline btn-sm">
          Edit profile
        </Link>
        <Link to="/shop" className="btn btn-primary btn-sm">
          Shop
        </Link>
      </div>
    </div>
  );
}
